// generate-import-fixtures converts TPC-H CSV fixtures into other file formats
// (AVRO, etc.) for use in IMPORT roachtests. It reads pipe-delimited .tbl files
// generated by dbgen and writes the output in the specified format.
//
// Usage:
//
//	go run ./pkg/cmd/generate-import-fixtures \
//	    --format=avro \
//	    --input-dir=/tmp/tpch-csv \
//	    --output-dir=/tmp/fixtures \
//	    --tables=customer,supplier
package main

import (
	"bufio"
	"flag"
	"fmt"
	"io"
	"log"
	"os"
	"path/filepath"
	"strings"
)

// batchSize is the number of rows parsed and written per batch. This bounds
// peak memory usage to roughly 15-20 MB regardless of shard size.
const batchSize = 10000

var formats = map[string]OutputFormat{
	"avro":    &avroFormat{},
	"parquet": &parquetFormat{},
}

func main() {
	formatName := flag.String("format", "avro", "output format (avro, parquet)")
	inputDir := flag.String("input-dir", "", "local directory containing TPC-H .tbl files (required)")
	outputDir := flag.String("output-dir", "", "local directory to write output files (required)")
	tablesFlag := flag.String("tables", "", "comma-separated list of tables (default: all)")
	flag.Parse()

	if *outputDir == "" {
		log.Fatal("--output-dir is required")
	}
	if *inputDir == "" {
		log.Fatal("--input-dir is required")
	}

	format, ok := formats[*formatName]
	if !ok {
		log.Fatalf("unknown format: %s (available: %s)", *formatName, availableFormats())
	}

	tables := allTPCHTables()
	if *tablesFlag != "" {
		tables = strings.Split(*tablesFlag, ",")
	}

	if err := os.MkdirAll(*outputDir, 0755); err != nil {
		log.Fatalf("creating output directory: %v", err)
	}

	// Write schema files.
	schemaDir := filepath.Join(*outputDir, "schema")
	if err := os.MkdirAll(schemaDir, 0755); err != nil {
		log.Fatalf("creating schema directory: %v", err)
	}

	for _, tableName := range tables {
		tableDef, err := getTPCHTable(tableName)
		if err != nil {
			log.Fatal(err)
		}
		if err := format.WriteSchema(tableDef, schemaDir); err != nil {
			log.Fatalf("writing schema for %s: %v", tableName, err)
		}
	}

	// Process each table's shards.
	for _, tableName := range tables {
		tableDef, err := getTPCHTable(tableName)
		if err != nil {
			log.Fatal(err)
		}
		fmt.Printf("processing table: %s\n", tableName)

		for shardIdx := 1; shardIdx <= 8; shardIdx++ {
			fileName := fmt.Sprintf("%s.tbl.%d", tableName, shardIdx)
			filePath := filepath.Join(*inputDir, fileName)

			f, err := os.Open(filePath)
			if err != nil {
				log.Fatalf("opening %s: %v", filePath, err)
			}

			writer, err := format.NewWriter(tableDef, *outputDir, shardIdx)
			if err != nil {
				f.Close()
				log.Fatalf("creating writer for %s shard %d: %v", tableName, shardIdx, err)
			}

			if _, err := processShard(f, tableDef, writer); err != nil {
				_ = writer.Close()
				f.Close()
				log.Fatalf("processing %s shard %d: %v", tableName, shardIdx, err)
			}

			if err := writer.Close(); err != nil {
				f.Close()
				log.Fatalf("closing writer for %s shard %d: %v", tableName, shardIdx, err)
			}
			f.Close()
		}
	}

	fmt.Println("done")
}

func availableFormats() string {
	names := make([]string, 0, len(formats))
	for name := range formats {
		names = append(names, name)
	}
	return strings.Join(names, ", ")
}

// processShard reads a pipe-delimited TPC-H file and streams parsed rows to the
// writer in fixed-size batches. It returns the total number of rows processed.
func processShard(r io.Reader, table TableDef, writer FormatWriter) (int, error) {
	scanner := bufio.NewScanner(r)
	// Increase buffer size for lineitem which can have long lines.
	scanner.Buffer(make([]byte, 0, 1024*1024), 1024*1024)

	batch := make([]map[string]interface{}, 0, batchSize)
	lineNum := 0
	totalRows := 0

	for scanner.Scan() {
		lineNum++
		line := scanner.Text()
		if line == "" {
			continue
		}
		fields := strings.Split(line, "|")
		// Strip trailing empty field from dbgen's trailing pipe.
		if len(fields) > 0 && fields[len(fields)-1] == "" {
			fields = fields[:len(fields)-1]
		}
		if len(fields) != len(table.Columns) {
			return totalRows, fmt.Errorf(
				"line %d: expected %d fields for %s, got %d",
				lineNum, len(table.Columns), table.Name, len(fields))
		}
		row := make(map[string]interface{}, len(table.Columns))
		for i, col := range table.Columns {
			val, err := col.Parse(fields[i])
			if err != nil {
				return totalRows, fmt.Errorf(
					"line %d, column %s: %w", lineNum, col.Name, err)
			}
			row[col.Name] = val
		}
		batch = append(batch, row)

		if len(batch) >= batchSize {
			if err := writer.WriteBatch(batch); err != nil {
				return totalRows, err
			}
			totalRows += len(batch)
			batch = batch[:0]
		}
	}
	if err := scanner.Err(); err != nil {
		return totalRows, err
	}

	// Flush final partial batch.
	if len(batch) > 0 {
		if err := writer.WriteBatch(batch); err != nil {
			return totalRows, err
		}
		totalRows += len(batch)
	}

	return totalRows, nil
}
